local xml = require("xml") -- Load the LuaXML library

function handle_xml_request(body)
  local parsed_xml = xml.parse(body) -- Parse the XML from request body
  local data = {} -- Create a table to store extracted data

  for _, node in ipairs(parsed_xml) do
    if node:get_name() == "root" then
